define i16 @lshr_shl_pow2_const_case2(i16 %x) !prof !0 {
  %lshr1 = lshr i16 8192, %x
  %shl = shl i16 %lshr1, 4
  %r = and i16 %shl, 32
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i8 @lshr_bitwidth_mask(i8 %x, i8 %y) {
  %sign = lshr i8 %x, 7
  %r = and i8 %sign, %y
  ret i8 %r
}

define i16 @invert_signbit_splat_mask(i8 %x, i16 %y) !prof !0 {
  %a = ashr i8 %x, 7
  %n = xor i8 %a, -1
  %s = sext i8 %n to i16
  %r = and i16 %s, %y
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

@g = external global i64

define i64 @test_and_or_constexpr_infloop() {
  %and = and i64 ptrtoint (ptr @g to i64), -8
  %or = or i64 %and, 1
  ret i64 %or
}

define i16 @shl_lshr_pow2_const_case1(i16 %x) !prof !0 {
  %shl = shl i16 4, %x
  %lshr = lshr i16 %shl, 6
  %r = and i16 %lshr, 8
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @add_constant_equal_with_the_top_bit_of_demandedbits_insertpt(i32 %x, i32 %y) {
  %add = add i32 %x, 16
  %or = or i32 %add, %y
  %and = and i32 %or, 24
  ret i32 %and
}

define i32 @and_sext_multiuse(i32 %x, i32 %y, i32 %a, i32 %b) !prof !0 {
  %cmp = icmp sgt i32 %x, %y
  %sext = sext i1 %cmp to i32
  %and1 = and i32 %sext, %a
  %and2 = and i32 %sext, %b
  %add = add i32 %and1, %and2
  ret i32 %add
}

!0 = !{!"function_entry_count", i64 1000}

define i16 @lshr_lshr_pow2_const_negative_overflow(i16 %x) {
  %lshr1 = lshr i16 -32768, %x
  %lshr2 = lshr i16 %lshr1, 15
  %r = and i16 %lshr2, 4
  ret i16 %r
}

define <3 x i16> @shl_lshr_pow2_const_case1_poison3_vec(<3 x i16> %x) {
  %shl = shl <3 x i16> splat (i16 16), %x
  %lshr = lshr <3 x i16> %shl, splat (i16 5)
  %r = and <3 x i16> %lshr, <i16 poison, i16 8, i16 8>
  ret <3 x i16> %r
}

define i8 @not_lshr_bitwidth_mask(i8 %x, i8 %y) {
  %sign = lshr i8 %x, 7
  %not = xor i8 %sign, -1
  %r = and i8 %not, %y
  ret i8 %r
}

define i8 @negate_lowbitmask(i8 %x, i8 %y) !prof !0 {
  %a = and i8 %x, 1
  %n = sub i8 0, %a
  %r = and i8 %n, %y
  ret i8 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i16 @signbit_splat_mask(i8 %x, i16 %y) !prof !0 {
  %a = ashr i8 %x, 7
  %s = sext i8 %a to i16
  %r = and i16 %s, %y
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @and_zext(i32 %a, i1 %b) !prof !0 {
  %mask = zext i1 %b to i32
  %r = and i32 %a, %mask
  ret i32 %r
}

!0 = !{!"function_entry_count", i64 1000}

define <3 x i16> @lshr_shl_pow2_const_case1_poison3_vec(<3 x i16> %x) {
  %lshr = lshr <3 x i16> splat (i16 8192), %x
  %shl = shl <3 x i16> %lshr, splat (i16 6)
  %r = and <3 x i16> %shl, <i16 poison, i16 128, i16 128>
  ret <3 x i16> %r
}

define i16 @lshr_shl_pow2_const_case1(i16 %x) !prof !0 {
  %lshr1 = lshr i16 256, %x
  %shl = shl i16 %lshr1, 2
  %r = and i16 %shl, 8
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i16 @shl_lshr_pow2_const_case2(i16 %x) !prof !0 {
  %shl = shl i16 16, %x
  %lshr = lshr i16 %shl, 3
  %r = and i16 %lshr, 8
  ret i16 %r
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @test_with_1(i32 %x) {
  %shl = shl i32 1, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i64 @and_add_non_bool(ptr %ptr, i64 %c) {
  %val = load i8, ptr %ptr, align 1, !range !0
  %rhs = zext i8 %val to i64
  %mask = add i64 -1, %rhs
  %res = and i64 %mask, %c
  ret i64 %res
}

!0 = !{i8 0, i8 3}

define i64 @PR63321(ptr %ptr, i64 %c) !prof !0 {
  %val = load i8, ptr %ptr, align 1, !range !1
  %rhs = zext i8 %val to i64
  %mask = add i64 -1, %rhs
  %res = and i64 %mask, %c
  ret i64 %res
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{i8 0, i8 2}

define i32 @and_add_bool_no_fold(i32 %y) !prof !0 {
  %x = and i32 %y, 1
  %mask = add i32 -1, %x
  %res = and i32 %mask, %y
  ret i32 %res
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @or_sext_to_sel(i32 %x, i1 %y) !prof !0 {
  %sext = sext i1 %y to i32
  %r = or i32 %sext, %x
  ret i32 %r
}

!0 = !{!"function_entry_count", i64 1000}

declare void @use_vec(<2 x i32>)

define <2 x i32> @and_not_sext_to_sel(<2 x i32> %x, <2 x i1> %y) !prof !0 {
  %sext = sext <2 x i1> %y to <2 x i32>
  call void @use_vec(<2 x i32> %sext)
  %not = xor <2 x i32> %sext, splat (i32 -1)
  %r = and <2 x i32> %not, %x
  ret <2 x i32> %r
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @and_add_bool_to_select(i1 %x, i32 %y) {
  %val = zext i1 %x to i32
  %mask = add i32 -1, %val
  %res = and i32 %mask, %y
  ret i32 %res
}

define i8 @t0(i8 %x, i1 %cond) !prof !0 {
  %cond.splat = sext i1 %cond to i8
  %sub = add i8 %cond.splat, %x
  %xor = xor i8 %sub, %cond.splat
  ret i8 %xor
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @sub_ashr_or_i32_extra_use_sub(i32 %x, i32 %y, ptr %p) !prof !0 {
  %sub = sub nsw i32 %y, %x
  store i32 %sub, ptr %p, align 4
  %shr = ashr i32 %sub, 31
  %or = or i32 %shr, %x
  ret i32 %or
}

!0 = !{!"function_entry_count", i64 1000}

define i32 @sub_ashr_or_i32_shift_wrong_bit(i32 %x, i32 %y) {
  %sub = sub nsw i32 %y, %x
  %shr = ashr i32 %sub, 11
  %or = or i32 %shr, %x
  ret i32 %or
}
